#include "conv_depthwise_2d_asymmetric_input_asymmetric_kernel_custom_tiling.h"
#include "register/op_def_registry.h"

namespace {
static inline int64_t FloorDiv(int64_t a, int64_t b) { return a / b; }

static inline int64_t ConvOutDim(int64_t in, int64_t pad, int64_t dilation, int64_t k, int64_t stride)
{
    // PyTorch conv2d output formula
    return FloorDiv(in + 2 * pad - dilation * (k - 1) - 1, stride) + 1;
}

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}
} // namespace

namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // conservative per-core UB share
static constexpr uint32_t ALIGN_ELEMS = 256;
static constexpr uint32_t HARD_CAP_ELEMS = 32768;        // avoid too-large per-iter latency

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvDepthwise2dAsymmetricInputAsymmetricKernelCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    // Expect x: [N, C, H, W] and weight: [C, 1, Kh, Kw] for depthwise
    int64_t N = (x_shape->GetDimNum() >= 1) ? x_shape->GetDim(0) : 1;
    int64_t C = (x_shape->GetDimNum() >= 2) ? x_shape->GetDim(1) : 1;
    int64_t H = (x_shape->GetDimNum() >= 3) ? x_shape->GetDim(2) : 1;
    int64_t W = (x_shape->GetDimNum() >= 4) ? x_shape->GetDim(3) : 1;

    int64_t Kh = (w_shape->GetDimNum() >= 3) ? w_shape->GetDim(2) : 1;
    int64_t Kw = (w_shape->GetDimNum() >= 4) ? w_shape->GetDim(3) : 1;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *stride_h = attrs->GetAttrPointer<int64_t>(0);
    const int64_t *stride_w = attrs->GetAttrPointer<int64_t>(1);
    const int64_t *pad_h    = attrs->GetAttrPointer<int64_t>(2);
    const int64_t *pad_w    = attrs->GetAttrPointer<int64_t>(3);
    const int64_t *dil_h    = attrs->GetAttrPointer<int64_t>(4);
    const int64_t *dil_w    = attrs->GetAttrPointer<int64_t>(5);

    int64_t OH = ConvOutDim(H, *pad_h, *dil_h, Kh, *stride_h);
    int64_t OW = ConvOutDim(W, *pad_w, *dil_w, Kw, *stride_w);

    if (OH < 0) OH = 0;
    if (OW < 0) OW = 0;

    // UB planning:
    // We will hold ySegment (L), xSegment (L) and a temp buffer (L)
    // Total floats ~ 3 * L => bytes ~ 12 * L
    uint32_t maxTile = UB_BUDGET_BYTES / 12;
    if (maxTile > HARD_CAP_ELEMS) maxTile = HARD_CAP_ELEMS;
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile == 0) maxTile = ALIGN_ELEMS;

    uint32_t totalOut = static_cast<uint32_t>(N * C * OH * OW);
    uint32_t tileLen = maxTile;
    if (static_cast<uint64_t>(totalOut) < static_cast<uint64_t>(tileLen)) {
        uint32_t aligned = AlignDown(totalOut, ALIGN_ELEMS);
        tileLen = (aligned > 0) ? aligned : totalOut;
    }

    uint32_t numTiles = (tileLen == 0) ? 1u : CeilDiv(totalOut, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_n(static_cast<uint32_t>(N));
    tiling.set_c(static_cast<uint32_t>(C));
    tiling.set_h(static_cast<uint32_t>(H));
    tiling.set_w(static_cast<uint32_t>(W));
    tiling.set_kh(static_cast<uint32_t>(Kh));
    tiling.set_kw(static_cast<uint32_t>(Kw));
    tiling.set_stride_h(static_cast<uint32_t>(*stride_h));
    tiling.set_stride_w(static_cast<uint32_t>(*stride_w));
    tiling.set_pad_h(static_cast<uint32_t>(*pad_h));
    tiling.set_pad_w(static_cast<uint32_t>(*pad_w));
    tiling.set_dil_h(static_cast<uint32_t>(*dil_h));
    tiling.set_dil_w(static_cast<uint32_t>(*dil_w));
    tiling.set_oh(static_cast<uint32_t>(OH));
    tiling.set_ow(static_cast<uint32_t}(OW));
    tiling.set_totalOut(totalOut);
    tiling.set_tileLen(tileLen);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

